<template>
<div>
    <div class="container">
        <div class="row">
            <div class="col-xl">
                   <div class="v-popup-wrapper " ref="popup-wrapper">
                            </div>
        </div>
    </div>
     <div class="container">
        <div class="row">
 <div class="v-popup">
    
            <div class="v-popup-header">
     
        </div>
        <div class="v-popup-content">
            <slot></slot>
        </div>
        <div class="v-popup-footer"></div>
     
     
    </div>
        </div>
     </div>
</div>
    
 
</div>

   
</template>

<script>
export default {
    name: "v-popup",
    props: {},
    data(){
        return{}
    },
    methods:{
        closePopup(){
            this.$emit('closePopup')
        }
    },
    mounted() {
        let vm = this;
        document.addEventListener('click', function(item){
            if(item.target === vm.$refs['popup-wrapper']) {
                vm.closePopup()
            }
        })
    },
}
</script>

<style >

